#include <stdio.h>
int main() {
    int Q;
    scanf("%d", &Q);
    while (Q--) {
        int a, b;
        scanf("%d %d", &a, &b);
        if ((a % 2 == b % 2 && abs(a - b) == 1) || abs(a - b) == 2) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

