code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int Q = sc.nextInt();
        while (Q-- > 0) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            if ((a % 2 == b % 2 && Math.abs(a - b) == 1) || Math.abs(a - b) == 2) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

